import React, { createContext, useContext, useEffect, useMemo, useReducer } from 'react';
import {
  ActivityIndicator,
  Alert,
  Button,
  SafeAreaView,
  StyleSheet,
  Text,
  TextInput,
  View,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_KEYS = {
  TOKEN: '@mvp_auth_token',
  USER: '@mvp_auth_user',
};

const AuthContext = createContext(null);

const initialState = {
  isLoading: true,
  token: null,
  user: null,
};

function authReducer(state, action) {
  switch (action.type) {
    case 'RESTORE_SESSION':
      return {
        ...state,
        isLoading: false,
        token: action.token,
        user: action.user,
      };
    case 'SIGN_IN':
      return {
        ...state,
        isLoading: false,
        token: action.token,
        user: action.user,
      };
    case 'SIGN_OUT':
      return {
        ...state,
        isLoading: false,
        token: null,
        user: null,
      };
    default:
      return state;
  }
}

async function persistSession(token, user) {
  await AsyncStorage.multiSet([
    [STORAGE_KEYS.TOKEN, token],
    [STORAGE_KEYS.USER, JSON.stringify(user)],
  ]);
}

async function clearSession() {
  await AsyncStorage.multiRemove([STORAGE_KEYS.TOKEN, STORAGE_KEYS.USER]);
}

async function restoreSession() {
  const entries = await AsyncStorage.multiGet([STORAGE_KEYS.TOKEN, STORAGE_KEYS.USER]);
  const map = Object.fromEntries(entries);
  const token = map[STORAGE_KEYS.TOKEN];
  const userString = map[STORAGE_KEYS.USER];

  if (!token || !userString) {
    return { token: null, user: null };
  }

  try {
    const user = JSON.parse(userString);
    return { token, user };
  } catch {
    await clearSession();
    return { token: null, user: null };
  }
}

async function fakeAuthApi({ email, password }) {
  await new Promise(resolve => setTimeout(resolve, 1000));

  if (!email || !password) {
    throw new Error('Email and password are required.');
  }

  if (password.length < 4) {
    throw new Error('Password must be at least 4 characters.');
  }

  return {
    token: `token_${Date.now()}`,
    user: {
      id: 'user_1',
      name: 'MVP User',
      email: email.trim().toLowerCase(),
    },
  };
}

export function AuthProvider({ children }) {
  const [state, dispatch] = useReducer(authReducer, initialState);

  useEffect(() => {
    let isMounted = true;

    const bootstrap = async () => {
      try {
        const { token, user } = await restoreSession();
        if (isMounted) {
          dispatch({ type: 'RESTORE_SESSION', token, user });
        }
      } catch {
        if (isMounted) {
          dispatch({ type: 'RESTORE_SESSION', token: null, user: null });
        }
      }
    };

    bootstrap();

    return () => {
      isMounted = false;
    };
  }, []);

  const value = useMemo(
    () => ({
      ...state,
      signIn: async (email, password) => {
        const response = await fakeAuthApi({ email, password });
        await persistSession(response.token, response.user);
        dispatch({
          type: 'SIGN_IN',
          token: response.token,
          user: response.user,
        });
      },
      signOut: async () => {
        await clearSession();
        dispatch({ type: 'SIGN_OUT' });
      },
    }),
    [state]
  );

  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

function SplashScreen() {
  return (
    <SafeAreaView style={styles.centered}>
      <ActivityIndicator size="large" />
      <Text style={styles.subtitle}>Restoring session...</Text>
    </SafeAreaView>
  );
}

function LoginScreen() {
  const { signIn } = useAuth();
  const [email, setEmail] = React.useState('');
  const [password, setPassword] = React.useState('');
  const [submitting, setSubmitting] = React.useState(false);

  const handleLogin = async () => {
    try {
      setSubmitting(true);
      await signIn(email, password);
    } catch (error) {
      Alert.alert('Login failed', error.message || 'Something went wrong.');
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Welcome</Text>
        <Text style={styles.subtitle}>Sign in to continue</Text>

        <TextInput
          autoCapitalize="none"
          autoCorrect={false}
          keyboardType="email-address"
          placeholder="Email"
          style={styles.input}
          value={email}
          onChangeText={setEmail}
        />

        <TextInput
          secureTextEntry
          placeholder="Password"
          style={styles.input}
          value={password}
          onChangeText={setPassword}
        />

        <Button
          title={submitting ? 'Signing In...' : 'Sign In'}
          onPress={handleLogin}
          disabled={submitting}
        />
      </View>
    </SafeAreaView>
  );
}

function HomeScreen() {
  const { user, token, signOut } = useAuth();
  const [loading, setLoading] = React.useState(false);

  const handleLogout = async () => {
    try {
      setLoading(true);
      await signOut();
    } catch {
      Alert.alert('Logout failed', 'Unable to clear session.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>You are logged in</Text>
        <Text style={styles.info}>Name: {user?.name}</Text>
        <Text style={styles.info}>Email: {user?.email}</Text>
        <Text style={styles.info}>Token: {token}</Text>
        <View style={styles.spacer} />
        <Button title={loading ? 'Signing Out...' : 'Sign Out'} onPress={handleLogout} disabled={loading} />
      </View>
    </SafeAreaView>
  );
}

function AuthGate() {
  const { isLoading, token } = useAuth();

  if (isLoading) {
    return <SplashScreen />;
  }

  return token ? <HomeScreen /> : <LoginScreen />;
}

export default function App() {
  return (
    <AuthProvider>
      <AuthGate />
    </AuthProvider>
  );
}

